// ============================================================
// Process Chunk Throttle Queue
// ------------------------------------------------------------
// Sits in front of the "Grant fetch - Process Chunk" webhook.
// Producers (Grant fetch's Process Chunk (Webhook) node) POST
// a batch of grants for a single org to /webhook/process-chunk-queue;
// this workflow unrolls them one grant at a time with a small delay
// between calls, so the Process Chunk task runner isn't hit with a
// multi-grant AI classification load in a single execution - which
// was OOMing the task runner.
//
// Pattern: recursive self-dispatch (same as Enrich + Screen queues).
// Ack returns 202 immediately; the Code node POSTs one grant to
// PROCESS_URL (preserving org context), sleeps DELAY_MS, then POSTs
// the tail back to QUEUE_URL (self) as a brand-new execution. Each
// Process Chunk execution handles exactly one grant - constant
// memory footprint no matter how big the org's grant list is.
//
// IMPORTANT: fire-and-forget. Process Chunk must write its results
// back to Supabase itself (it already does - 'Insert Into Central
// Grants' + screener webhook fan-out inside Process Chunk). The
// producer does NOT see per-grant classification results inline.
//
// Expected input (webhook body):
//   { org_id, org, nicheSummary, callbackUrl, chunk_index,
//     total_chunks, grants: [ { id, title, ... }, ... ] }
// The org-level context is preserved on every forwarded call so
// Process Chunk has everything it needs to classify one grant.
// ============================================================

const DELAY_MS    = 500;
const TIMEOUT_MS  = 120000;
const MAX_RETRIES = 2;
const PROCESS_URL = 'https://n8n.thebrownmine.com/webhook/process-grant-chunk';
const QUEUE_URL   = 'https://n8n.thebrownmine.com/webhook/process-chunk-queue';

const helpers = this.helpers;
const raw = $input.first().json;
const input = raw.body || raw;

const grants = Array.isArray(input.grants) ? input.grants : [];

if (grants.length === 0) {
  return [{ json: { success: true, forwarded: 0, org_id: input.org_id || null } }];
}

const head = grants[0];
const tail = grants.slice(1);

// Preserve org-level context on every forwarded call.
const context = {
  org_id:        input.org_id,
  org:           input.org,
  nicheSummary:  input.nicheSummary,
  callbackUrl:   input.callbackUrl,
  chunk_index:   input.chunk_index,
  total_chunks:  input.total_chunks,
};

async function post(url, body, attempt) {
  attempt = attempt || 0;
  try {
    await helpers.httpRequest({
      method:  'POST',
      url:     url,
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify(body),
      timeout: TIMEOUT_MS,
    });
    return { ok: true };
  } catch (e) {
    const status = e.httpCode || e.statusCode || (e.response && e.response.status);
    const transient = status === 429 || (status >= 500 && status < 600) || !status;
    if (transient && attempt < MAX_RETRIES) {
      const backoff = Math.min(5000, 500 * Math.pow(2, attempt)) + Math.floor(Math.random() * 250);
      await new Promise(function (r) { setTimeout(r, backoff); });
      return post(url, body, attempt + 1);
    }
    return { ok: false, status: status, message: String(e.message || e).slice(0, 400) };
  }
}

const processResult = await post(PROCESS_URL, Object.assign({}, context, { grants: [head] }));

if (tail.length > 0) {
  await new Promise(function (r) { setTimeout(r, DELAY_MS); });
  await post(QUEUE_URL, Object.assign({}, context, { grants: tail }));
}

return [{
  json: {
    success:          true,
    org_id:           context.org_id || null,
    forwardedGrantId: head && (head.id || head.grant_id || null),
    processResult:    processResult,
    remaining:        tail.length,
  },
}];
